export const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 1000 * 60 * 5,
      gcTime: 1000 * 60 * 10,
      retry: (failureCount, error: unknown) => {
        if (axios.isAxiosError(error)) {
          const status = error.response?.status;
          if (status === 401 || status === 403 || status === 404) return false;
        }
        return failureCount < 2;
      },
      refetchOnWindowFocus: false,
    },
    mutations: {
      onError: (error: unknown) => {
        const message = axios.isAxiosError(error)
          ? (error.response?.data?.message ?? 'Что-то пошло не так')
          : 'Что-то пошло не так';
        toast.error(message);
      },
    },
  },
});

import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return !!isMobile
}

import {
  useQuery,
  useMutation,
  useInfiniteQuery,
  useQueryClient,
  type UseQueryOptions,
  type UseMutationOptions,
  type UseInfiniteQueryOptions,
  type InfiniteData,
} from '@tanstack/react-query';
import { toast } from 'sonner';
import apiClient from '@/config/axios';
import type { AxiosRequestConfig } from 'axios';

// ── Types ──────────────────────────────────────────────────────

export interface PaginatedResponse<T> {
  data: T[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
}

// ── Base fetcher ───────────────────────────────────────────────

export async function apiFetch<T>(
  url: string,
  config?: AxiosRequestConfig
): Promise<T> {
  const res = await apiClient.request<T>({ url, ...config });
  return res.data;
}

// ── useApiQuery ────────────────────────────────────────────────

/**
 * Обёртка над useQuery для GET-запросов.
 *
 * @example
 * const { data } = useApiQuery<User[]>(['users'], '/users');
 */
export function useApiQuery<T>(
  queryKey: unknown[],
  url: string,
  config?: AxiosRequestConfig,
  options?: Omit<UseQueryOptions<T>, 'queryKey' | 'queryFn'>
) {
  return useQuery<T>({
    queryKey,
    queryFn: () => apiFetch<T>(url, config),
    ...options,
  });
}

// ── useApiMutation ─────────────────────────────────────────────

interface MutationConfig<TData, TVariables> {
  url: string | ((variables: TVariables) => string);
  method?: 'POST' | 'PUT' | 'PATCH' | 'DELETE';
  successMessage?: string;
  invalidateKeys?: unknown[][];
  options?: UseMutationOptions<TData, Error, TVariables>;
}

/**
 * Обёртка над useMutation для POST/PUT/PATCH/DELETE.
 *
 * @example
 * const createUser = useApiMutation<User, CreateUserDto>({
 *   url: '/users',
 *   method: 'POST',
 *   successMessage: 'Пользователь создан',
 *   invalidateKeys: [['users']],
 * });
 */

export function useApiMutation<TData = unknown, TVariables = void>({
  url,
  method = 'POST',
  successMessage,
  invalidateKeys = [],
  options,
}: MutationConfig<TData, TVariables>) {
  const qc = useQueryClient();

  return useMutation<TData, Error, TVariables>({
    mutationFn: async (variables) => {
      const resolvedUrl = typeof url === 'function' ? url(variables) : url;
      const res = await apiClient.request<TData>({
        url: resolvedUrl,
        method,
        data: method !== 'DELETE' ? variables : undefined,
      });
      return res.data;
    },
    onSuccess: () => {
      if (successMessage) toast.success(successMessage);
      invalidateKeys.forEach((key) => qc.invalidateQueries({ queryKey: key }));
    },
    ...options,
  });
}

// ── useApiInfiniteQuery ────────────────────────────────────────

/**
 * Обёртка для пагинированных списков (infinite scroll).
 *
 * @example
 * const { data, fetchNextPage } = useApiInfiniteQuery<Product>(
 *   ['products'],
 *   (page) => `/products?page=${page}&limit=20`
 * );
 */
export function useApiInfiniteQuery<T>(
  queryKey: unknown[],
  getUrl: (page: number) => string,
  options?: Omit<
    UseInfiniteQueryOptions<PaginatedResponse<T>, Error, InfiniteData<PaginatedResponse<T>>, PaginatedResponse<T>, unknown[], number>,
    'queryKey' | 'queryFn' | 'initialPageParam' | 'getNextPageParam'
  >
) {
  return useInfiniteQuery<
    PaginatedResponse<T>,
    Error,
    InfiniteData<PaginatedResponse<T>>,
    unknown[],
    number
  >({
    queryKey,
    queryFn: ({ pageParam }) => apiFetch<PaginatedResponse<T>>(getUrl(pageParam)),
    initialPageParam: 1,
    getNextPageParam: (last) =>
      last.page < last.totalPages ? last.page + 1 : undefined,
    ...options,
  });
}

import { useForm as useRHF, type DefaultValues, type UseFormProps } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import type { ZodSchema, z } from 'zod';

/**
 * Wrapper over react-hook-form + zod.
 * AI uses this hook for ALL forms.
 *
 * @example
 * const schema = z.object({ email: z.string().email() });
 * const form = useAppForm(schema, { email: '' });
 * // With custom mode:
 * const form = useAppForm(schema, { email: '' }, { mode: 'onChange' });
 */
export function useAppForm<TSchema extends ZodSchema>(
  schema: TSchema,
  defaultValues?: DefaultValues<z.infer<TSchema>>,
  options?: Omit<UseFormProps<z.infer<TSchema>>, 'resolver' | 'defaultValues'>
) {
  return useRHF<z.infer<TSchema>>({
    resolver: zodResolver(schema),
    defaultValues,
    mode: 'onBlur',
    ...options,
  });
}

